import{_ as e,o as t,c as s,a5 as l}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"概念：三相 SRF-PLL 锁相","description":"","frontmatter":{"date":"2026-06-22T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：三相 SRF-PLL 锁相","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0038-three-phase-srf-pll.html` 的源稿。只记录公开锁相结构，不记录内部参数。"},"headers":[],"relativePath":"content/power/concepts/control/three-phase-srf-pll.md","filePath":"content/power/concepts/control/three-phase-srf-pll.md","lastUpdated":null}'),r={name:"content/power/concepts/control/three-phase-srf-pll.md"};function n(o,a,i,p,h,c){return t(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="概念-三相-srf-pll-锁相" tabindex="-1">概念：三相 SRF-PLL 锁相 <a class="header-anchor" href="#概念-三相-srf-pll-锁相" aria-label="Permalink to &quot;概念：三相 SRF-PLL 锁相&quot;">​</a></h1><p>本页是 <code>lessons/0038-three-phase-srf-pll.html</code> 的源稿。只记录公开锁相结构，不记录内部参数。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>同步旋转坐标系锁相环（synchronous reference frame PLL / SRF-PLL）用三相电压的 q 轴误差调整估算频率和相位，使 q 轴电压收敛到 0。</p><h2 id="为什么-ups-pcs-需要它" tabindex="-1">为什么 UPS/PCS 需要它 <a class="header-anchor" href="#为什么-ups-pcs-需要它" aria-label="Permalink to &quot;为什么 UPS/PCS 需要它&quot;">​</a></h2><p>三相 PFC、并网 PCS 和旁路同步需要电网角度。PLL 失锁会让 dq 电流环和 P/Q 控制失去物理含义。</p><h2 id="数学形式" tabindex="-1">数学形式 <a class="header-anchor" href="#数学形式" aria-label="Permalink to &quot;数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vq = -v_alpha * sin(theta) + v_beta * cos(theta)</span></span>
<span class="line"><span>omega = omega_nominal + PI(0 - vq)</span></span>
<span class="line"><span>theta = theta + omega * Ts</span></span></code></pre></div><h2 id="一个仿真任务" tabindex="-1">一个仿真任务 <a class="header-anchor" href="#一个仿真任务" aria-label="Permalink to &quot;一个仿真任务&quot;">​</a></h2><p>加入初始相位误差，观察 vq、theta_err 和 f_est 收敛；再加入电压跌落，观察锁定状态。</p><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能说明为什么控制 vq 到 0 就能锁相。</li><li>能画出 vabc -&gt; Clarke -&gt; Park -&gt; PI -&gt; theta。</li><li>能区分单相 PLL 和三相 PLL 的正交信号来源。</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><p>PLL 失锁在真实工程中通常如何传递给状态机？只记录公开原则。</p>`,14)])])}const P=e(r,[["render",n]]);export{u as __pageData,P as default};
